#!/usr/bin/env python3
import os, base64, re as _re

files = [
  ('app\\\\api\\\\admin\\\\auth\\\\route.ts', ''),
  ('app\\\\admin\\\\page.tsx', ''),
  ('app\\\\terms\\\\page.tsx', ''),
  ('app\\\\forecast\\\\page.tsx', ''),
  ('app\\\\dashboard\\\\page.tsx', ''),
  ('components\\\\Sidebar.tsx', ''),
  ('app\\\\api\\\\onboarding\\\\complete\\\\route.ts', ''),
  ('app\\\\api\\\\onboarding\\\\confirm-email\\\\route.ts', ''),
  ('app\\\\api\\\\chat\\\\route.ts', ''),
  ('app\\\\notebook\\\\page.tsx', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "wb") as f:
        f.write(content.encode("utf-8"))
    print(f"Written: {path}")

print("\nAll files written.")
print("Now run:")
print("  git add .")
print("  git commit -m \"Session 6: terms, admin security, sync status, forecast empty state, AI limits, confirmation email\"")
print("  vercel --prod")
